import{c as r,Q as t,j as a,m as s}from"./chunks/framework.BBA2dIOt.js";const g=JSON.parse('{"title":"Screenshots","description":"","frontmatter":{},"headers":[],"relativePath":"screenshots.md","filePath":"screenshots.md","lastUpdated":1779767166000}'),o={name:"screenshots.md"};function i(l,e,n,d,c,h){return t(),a("div",null,[...e[0]||(e[0]=[s('<h1 id="screenshots" tabindex="-1">Screenshots <a class="header-anchor" href="#screenshots" aria-label="Permalink to &quot;Screenshots&quot;">​</a></h1><h2 id="three-pane-reader" tabindex="-1">Three-pane reader <a class="header-anchor" href="#three-pane-reader" aria-label="Permalink to &quot;Three-pane reader&quot;">​</a></h2><p>The default layout: sidebar of folders + feeds, the article list, and the reader. Drag-to-reorder folders and feeds within them. Right-click any feed for mute, mark-all-read, resummarize, or delete.</p><h2 id="summary-card" tabindex="-1">Summary card <a class="header-anchor" href="#summary-card" aria-label="Permalink to &quot;Summary card&quot;">​</a></h2><p>The AI summary appears between the title and the article body. Paragraph lead + 3 factual bullets, with the source thumbnail inline. Collapsible per article; the preference persists per user.</p><h2 id="settings" tabindex="-1">Settings <a class="header-anchor" href="#settings" aria-label="Permalink to &quot;Settings&quot;">​</a></h2><p>Eight sections:</p><ul><li><strong>Profile</strong> — change your password.</li><li><strong>Preferences</strong> — theme picker (8 presets + custom 3-color editor), density (cards / compact), AI summary on/off, article images on/off, scroll-to-mark-read on/off.</li><li><strong>Reading stats</strong> — today / week / 30-day read counts, top feeds.</li><li><strong>Mobile clients</strong> — Fever URL + your random API token.</li><li><strong>Filters</strong> — manage hide/star/mark-read rules.</li><li><strong>Starter packs</strong> — one-click curated feed bundles (Technology / Programming / Security / DevOps / World News).</li><li><strong>Language model</strong> (admin) — host probe, current model, installed list with switch + delete, pull form, tuning sliders.</li><li><strong>Branding</strong> (admin) — name, page title, favicon URL.</li><li><strong>Database</strong> (admin) — size, manual + scheduled backups, cleanup, OPML export.</li><li><strong>Users</strong> (admin) — create, edit, delete user accounts.</li></ul><h2 id="mobile" tabindex="-1">Mobile <a class="header-anchor" href="#mobile" aria-label="Permalink to &quot;Mobile&quot;">​</a></h2><p>≤900px viewport: sidebar collapses into an off-canvas drawer. Article list and reader take turns at full width — selecting an article switches to the reader, the back button returns to the list. Below 520px, brand text hides so the search bar has room.</p><h2 id="themes" tabindex="-1">Themes <a class="header-anchor" href="#themes" aria-label="Permalink to &quot;Themes&quot;">​</a></h2><ul><li><strong>Auto</strong> — follows the OS <code>prefers-color-scheme</code>.</li><li><strong>Light</strong> / <strong>Dark</strong> — paper-and-ink defaults.</li><li><strong>Solarized</strong> — Ethan Schoonover&#39;s classic palette (light).</li><li><strong>Sepia</strong> — warm browns, e-reader friendly.</li><li><strong>Nord</strong> — cool blue-gray dark.</li><li><strong>Gruvbox</strong> — warm-tinted dark by morhetz.</li><li><strong>High contrast</strong> — black/white/yellow for low-vision users.</li><li><strong>Custom</strong> — pick 3 colors (paper, ink, accent), the rest derives via CSS <code>color-mix()</code>.</li></ul>',12)])])}const u=r(o,[["render",i]]);export{g as __pageData,u as default};
